  <script>
    (function () {
      const counters = document.querySelectorAll('.counter');
      const clockEl = document.getElementById('clock');
      const clockDateEl = document.getElementById('clockDate');
      const lastUpdatedEl = document.getElementById('lastUpdated');

      function pad(n) {
        return String(n).padStart(2, '0');
      }

      function formatNumber(value, decimals = 0) {
        return Number(value).toLocaleString('zh-CN', {
          minimumFractionDigits: decimals,
          maximumFractionDigits: decimals
        });
      }

      function updateClock() {
        const now = new Date();
        const y = now.getFullYear();
        const m = now.getMonth() + 1;
        const d = now.getDate();
        const hh = pad(now.getHours());
        const mm = pad(now.getMinutes());
        const ss = pad(now.getSeconds());
        const weekdays = ['星期日', '星期一', '星期二', '星期三', '星期四', '星期五', '星期六'];

        clockEl.textContent = `${hh}:${mm}:${ss}`;
        clockDateEl.textContent = `${y} 年 ${m} 月 ${d} 日 · ${weekdays[now.getDay()]}`;
      }

      function setLastUpdated() {
        const now = new Date();
        lastUpdatedEl.textContent = now.toLocaleString('zh-CN', {
          hour12: false
        });
      }

      function animateCounter(el) {
        if (el.dataset.animated === 'true') return;
        el.dataset.animated = 'true';

        const target = parseFloat(el.dataset.target || '0');
        const decimals = parseInt(el.dataset.decimals || '0', 10);
        const duration = target > 10000 ? 1800 : 1400;
        const startTime = performance.now();

        function step(currentTime) {
          const progress = Math.min((currentTime - startTime) / duration, 1);
          const eased = 1 - Math.pow(1 - progress, 3);
          const currentValue = target * eased;

          el.textContent = formatNumber(currentValue, decimals);

          if (progress < 1) {
            requestAnimationFrame(step);
          } else {
            el.textContent = formatNumber(target, decimals);
          }
        }

        requestAnimationFrame(step);
      }

      const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            const localCounters = entry.target.querySelectorAll('.counter');
            localCounters.forEach(animateCounter);
            observer.unobserve(entry.target);
          }
        });
      }, {
        threshold: 0.2
      });

      document.querySelectorAll('.section-card, .status-panel').forEach(section => {
        observer.observe(section);
      });

      counters.forEach(counter => {
        const card = counter.closest('.metric-card');
        if (card) observer.observe(card);
      });

      updateClock();
      setInterval(updateClock, 1000);
      setLastUpdated();

      window.addEventListener('load', () => {
        counters.forEach(animateCounter);
      });
    })();
  </script>
</body>
